# Math utilities module
# Provides base calculator class and factorial function

def factorial(n: int) -> int:
    if n <= 1:
        return 1
    return n * factorial(n - 1)

class Calculator:
    total: int

    def __init__(self, initial: int):
        self.total = initial

    @virtual
    def add(self, x: int) -> int:
        self.total += x
        return self.total

    @virtual
    def get_total(self) -> int:
        return self.total

