# Shapes module - demonstrates cross-module inheritance
# Imports base Calculator class from math_utils module

from math_utils import Calculator

class AdvancedCalculator(Calculator):
    product: int

    def __init__(self, initial: int):
        super().__init__(initial)
        self.product = 1

    @override
    def add(self, x: int) -> int:
        result = super().add(x)
        self.product *= x if x > 0 else 1
        return result

    def get_product(self) -> int:
        return self.product

def calculate_area(width: int, height: int) -> int:
    return width * height
